}

rules_version = '2';
service cloud.firestore {
  match /databases/{db}/documents {
    function isMember(tid) {
      return request.auth != null && request.auth.token.tenants.hasAny([tid]);
    }
    function hasRole(role) { return role in request.auth.token.roles; }
    match /tenants/{tid}/reports/{rid} {
      allow read: if isMember(tid);
      allow create: if isMember(tid) && hasRole('engineer');
      allow update: if isMember(tid) && hasRole('engineer') && request.resource.data.frozen == false;
      allow delete: if false;
      match /versions/{vid} {
        allow read: if isMember(tid);
        allow create: if isMember(tid) && hasRole('engineer');
        allow update: if false; // versions are immutable
        allow delete: if false;
      }
    }
  }
}

