import {chromium} from 'playwright';
export async function exportPdf(html: string, meta: Meta): Promise<Buffer> {
  const browser = await chromium.launch({args:['--no-sandbox']});
  const ctx = await browser.newContext();
  const page = await ctx.newPage();
  await page.setContent(html, {waitUntil:'networkidle'});
  const pdf = await page.pdf({format:'A4', printBackground:true,
    displayHeaderFooter:true,
    footerTemplate:`<div style="font-size:9px;width:100%;text-align:center">${meta.reportId} v${meta.version} · ${meta.contentHash} · ${meta.ts}</div>`,
    headerTemplate:'<span></span>'});
  await browser.close();
  return pdf;
}

import {trace, context, SpanStatusCode} from '@opentelemetry/api';
const tracer = trace.getTracer('promptmgmt');
export async function callLLM(req: LLMReq) {
  return tracer.startActiveSpan('agent.invoke', async (span) => {
    span.setAttributes({
      'gen_ai.system': req.provider,
      'gen_ai.request.model': req.model,
      'tenant.id': req.tenantId,
      'persona.id': req.personaId,
    });
    try {
      const r = await provider.chat(req);
      span.setAttributes({
        'gen_ai.usage.prompt_tokens': r.usage.prompt,
        'gen_ai.usage.completion_tokens': r.usage.completion,
        'gen_ai.response.id': r.id,
      });
      return r;
    } catch (e:any) {
      span.recordException(e); span.setStatus({code:SpanStatusCode.ERROR});
      throw e;
    } finally { span.end(); }
  });
}

import {createHash, sign} from 'node:crypto';
export async function appendEnvelope(prev: string, evt: Event, key: KeyHandle) {
  const body = canonicalize({...evt, prevHash: prev});
  const thisHash = createHash('sha256').update(body).digest('hex');
  const sig = sign('Ed25519', Buffer.from(thisHash,'hex'), key.priv);
  const envelope = {...JSON.parse(body), thisHash, signatures:[{alg:'Ed25519', kid:key.kid, sig:sig.toString('base64')}]};
  await kafka.send({topic:`audit.${evt.tenantId}`, messages:[{key:evt.envelopeId, value:JSON.stringify(envelope)}]});
  return envelope;
}

